framework_css:
/*
  Cozweat fitness landing framework
  Matches the cinematic rowing hero + bold blue header style
*/

:root {
  /* Core brand palette from design */
  --color-primary-300: #00c4ff; /* lighter cyan accent from wave and reflections */
  --color-primary-500: #0094ff; /* main bright brand blue (header/wave) */
  --color-primary-700: #0072cc; /* darker blue used for text on light */

  --color-secondary-700: #002a5c; /* deep navy accents */

  --color-accent-contrast: #ffffff;

  --color-neutral-900: #111111;
  --color-neutral-600: #666666;
  --color-neutral-100: #f5f5f5;

  --color-success: #2ecc71;
  --color-error: #e74c3c;
  --color-warning: #f1c40f;
  --color-info: #3498db;

  /* Typography */
  --font-heading: "Playfair Display", Georgia, serif;
  --font-body: "DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;

  --font-size-h1: 56px;
  --font-size-h2: 36px;
  --font-size-h3: 24px;
  --font-size-body: 16px;
  --font-size-small: 13px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  /* Spacing scale (8px base) */
  --space-0-5: 4px;
  --space-1: 8px;
  --space-2: 16px;
  --space-3: 24px;
  --space-4: 32px;
  --space-5: 48px;
  --space-6: 64px;

  /* Layout */
  --header-height: 72px;
  --max-width: 1200px;
  --radius-pill: 999px;
  --radius-card: 8px;
  --shadow-elevated: 0 10px 25px rgba(0, 0, 0, 0.35);
}

/* Global reset / base */

*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-accent-contrast);
  background-color: var(--color-neutral-900);
}

.page {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  background-color: var(--color-neutral-900);
  color: var(--color-accent-contrast);
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
a:focus-visible {
  text-decoration: underline;
}

main#content {
  flex: 1 0 auto;
  min-height: 0;
}

/* Header */

.site-header {
  background-color: var(--color-primary-500);
  color: var(--color-accent-contrast);
  position: relative;
  z-index: 10;
}

.header-inner {
  max-width: var(--max-width);
  margin: 0 auto;
  height: var(--header-height);
  padding: 0 var(--space-4);
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.header-left {
  display: flex;
  align-items: center;
  min-width: 0;
}

.brand {
  display: inline-flex;
  align-items: center;
  white-space: nowrap;
}

/* Logo mark: circular navy badge with cyan dots, approximating the design */

.brand-mark {
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  margin-right: var(--space-1);
  border-radius: 50%;
  background: radial-gradient(circle at 30% 30%, var(--color-primary-300), var(--color-secondary-700));
  box-shadow: 0 0 0 3px rgba(255, 255, 255, 0.3);
  overflow: hidden;
}

.brand-mark--small {
  width: 32px;
  height: 32px;
}

.brand-mark-dot {
  position: absolute;
  border-radius: 50%;
  background-color: var(--color-accent-contrast);
}

.brand-mark-dot--large {
  width: 12px;
  height: 12px;
  opacity: 0.95;
}

.brand-mark-dot--small {
  width: 7px;
  height: 7px;
  right: 6px;
  bottom: 10px;
  background-color: var(--color-primary-300);
}

.brand-mark-dot--smaller {
  width: 5px;
  height: 5px;
  left: 8px;
  top: 8px;
  background-color: var(--color-primary-300);
  opacity: 0.8;
}

.brand-text {
  display: flex;
  flex-direction: column;
  line-height: 1.1;
}

.brand-name {
  font-family: var(--font-body);
  font-size: 15px;
  font-weight: var(--font-weight-bold);
  letter-spacing: 0.18em;
  text-transform: uppercase;
}

.brand-tagline {
  font-size: 10px;
  letter-spacing: 0.25em;
  text-transform: uppercase;
  opacity: 0.8;
}

.header-app-label {
  margin-left: var(--space-3);
  font-size: 13px;
  letter-spacing: 0.3em;
  text-transform: uppercase;
  font-weight: var(--font-weight-medium);
}

/* Center navigation in white pill, echoing the design's central control */

.header-center {
  flex: 1 1 auto;
  display: flex;
  justify-content: center;
  padding: 0 var(--space-3);
}

.nav-pill {
  list-style: none;
  margin: 0;
  padding: 4px 24px;
  border-radius: var(--radius-pill);
  background-color: var(--color-accent-contrast);
  box-shadow: var(--shadow-elevated);
  display: flex;
  align-items: center;
  gap: var(--space-2);
  max-width: 100%;
  overflow-x: auto;
  scrollbar-width: none; /* Firefox */
}

.nav-pill::-webkit-scrollbar {
  display: none;
}

.nav-item {
  flex: 0 0 auto;
}

.nav-link {
  position: relative;
  display: inline-block;
  padding: 6px 12px;
  border-radius: var(--radius-pill);
  font-size: 13px;
  font-weight: var(--font-weight-medium);
  text-transform: uppercase;
  letter-spacing: 0.16em;
  color: var(--color-primary-700);
  white-space: nowrap;
}

.nav-link.is-active {
  background-color: var(--color-primary-700);
  color: var(--color-accent-contrast);
}

.nav-link:focus-visible {
  outline: 2px solid var(--color-primary-300);
  outline-offset: 2px;
}

.header-right {
  display: flex;
  align-items: center;
  gap: var(--space-2);
}

.header-icon {
  width: 32px;
  height: 32px;
  border-radius: var(--radius-pill);
  border: 1px solid rgba(255, 255, 255, 0.7);
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0.9;
}

/* Simple purely decorative icon approximations */

.header-icon--grid::before {
  content: "";
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  grid-template-rows: repeat(2, 1fr);
  gap: 2px;
  width: 14px;
  height: 14px;
  background-image:
    linear-gradient(var(--color-accent-contrast), var(--color-accent-contrast));
}

.header-icon--slider span {
  display: block;
  width: 3px;
  height: 14px;
  margin: 0 1px;
  border-radius: 999px;
  background-color: var(--color-accent-contrast);
}

.header-icon--menu {
  flex-direction: column;
  justify-content: center;
}

.header-icon--menu span {
  display: block;
  width: 18px;
  height: 2px;
  margin: 1px 0;
  border-radius: 999px;
  background-color: var(--color-accent-contrast);
}

/* Hero pattern (for pages that use it) */

.hero {
  position: relative;
  min-height: calc(100vh - var(--header-height));
  color: var(--color-accent-contrast);
  display: flex;
  align-items: center;
  padding: var(--space-5) var(--space-4) var(--space-6);
  background-color: #000;
  background-position: center center;
  background-size: cover;
  background-repeat: no-repeat;
  /* Example: background-image: url("images/hero-rowing.jpg"); */
}

.hero::after {
  /* subtle vignette for contrast over photography */
  content: "";
  position: absolute;
  inset: 0;
  background: radial-gradient(circle at 20% 20%, rgba(0, 0, 0, 0.15), transparent 55%),
              linear-gradient(to bottom, rgba(0, 0, 0, 0.4), rgba(0, 0, 0, 0.75));
  pointer-events: none;
}

.hero-inner {
  position: relative;
  max-width: var(--max-width);
  margin: 0 auto;
}

.hero-heading {
  font-family: var(--font-heading);
  font-size: var(--font-size-h1);
  font-weight: var(--font-weight-regular);
  line-height: var(--line-height-tight);
  letter-spacing: 0.1em;
  text-transform: uppercase;
}

.hero-subtitle {
  margin-top: var(--space-3);
  max-width: 480px;
  font-size: 15px;
  line-height: var(--line-height-relaxed);
  opacity: 0.9;
}

/* Footer */

.site-footer {
  position: relative;
  background-color: var(--color-secondary-700);
  color: var(--color-accent-contrast);
  margin-top: auto;
  overflow: hidden;
}

/* Curved blue band at top of footer, reflecting hero curve in design */

.footer-wave {
  position: absolute;
  top: -32px;
  left: 0;
  width: 100%;
  height: 64px;
  background-color: var(--color-primary-500);
  border-bottom-left-radius: 50% 100%;
  border-bottom-right-radius: 50% 100%;
}

.footer-inner {
  position: relative;
  max-width: var(--max-width);
  margin: 0 auto;
  padding: var(--space-5) var(--space-4) var(--space-3);
}

.footer-top {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-4);
  flex-wrap: wrap;
}

.footer-brand {
  display: inline-flex;
  align-items: center;
}

.footer-nav {
  flex: 1 1 auto;
}

.footer-links {
  list-style: none;
  display: flex;
  flex-wrap: wrap;
  justify-content: flex-end;
  gap: var(--space-2) var(--space-3);
  margin: 0;
  padding: 0;
}

.footer-link {
  font-size: var(--font-size-small);
  letter-spacing: 0.16em;
  text-transform: uppercase;
  opacity: 0.9;
}

.footer-link:hover,
.footer-link:focus-visible {
  opacity: 1;
}

.footer-bottom {
  margin-top: var(--space-3);
  font-size: var(--font-size-small);
  opacity: 0.8;
}

.footer-meta {
  margin: 0;
}

/* Utilities for headings within content sections */

h1,
h2,
h3,
h4,
h5,
h6 {
  font-family: var(--font-heading);
  margin-top: 0;
  color: var(--color-accent-contrast);
}

h1 {
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
}

h2 {
  font-size: var(--font-size-h2);
}

h3 {
  font-size: var(--font-size-h3);
}

p {
  margin-top: 0;
  margin-bottom: var(--space-2);
}

/* Responsive adjustments */

@media (max-width: 1024px) {
  .header-inner {
    padding-inline: var(--space-3);
  }

  .header-app-label {
    display: none;
  }
}

@media (max-width: 768px) {
  .header-inner {
    gap: var(--space-2);
  }

  .header-center {
    order: 3;
    margin-top: -4px;
    justify-content: flex-start;
  }

  .header-right {
    order: 2;
  }

  .footer-top {
    flex-direction: column;
    align-items: flex-start;
  }

  .footer-links {
    justify-content: flex-start;
  }
}

@media (max-width: 480px) {
  .nav-pill {
    padding-inline: var(--space-2);
  }

  .brand-name {
    font-size: 13px;
  }

  .brand-tagline {
    display: none;
  }
}
